function Save_setItem(name, value) {
    if (!isPrivate) localStorage.setItem(name, value)
}

function Save_getItem(name, pardefaut) {
    if (!isPrivate) return localStorage.getItem(name);
    else return pardefaut
}

function save_lire(str1) {
    sauvegarde = [];
    var str = str1.split(",");
    var ligne = 0;
    var ii = 0;
    while (ligne < str.length) {
        sauvegarde[ii] = {
            numetoile: 0,
            bestscore: 0
        };
        sauvegarde[ii].numetoile = +str[ligne++];
        sauvegarde[ii].bestscore = +str[ligne++];
        ii++
    }
}

function save_ecrit() {
    var str = "";
    for (var i = 0; i < nombre_levels; i++) {
        str += "" + sauvegarde[i].numetoile;
        str += ",";
        str += "" + sauvegarde[i].bestscore;
        if (i < nombre_levels - 1) str += ","
    }
    Save_setItem("fruit_sauvegarde", str)
}

function save_ecrit_char() {
    var str = "";
    for (var i = 0; i < 4; i++) {
        str += "" + save_characters[i].unlocked;
        str += ",";
        str += "" + save_characters[i].level;
        str += ",";
        str += "" + save_characters[i].points;
        if (i < 3) str += ","
    }
    Save_setItem("fruit_char", str)
}

function save_lire_char(str1) {
    save_characters = [];
    var str = str1.split(",");
    var ligne = 0;
    var ii = 0;
    while (ligne < str.length) {
        save_characters[ii] = {
            unlocked: 0,
            level: 1,
            points: 200
        };
        save_characters[ii].unlocked = +str[ligne++];
        save_characters[ii].level = +str[ligne++];
        save_characters[ii].points = +str[ligne++];
        ii++
    }
}
