twinsFamily = {};
twinsFamily.Boot = function(game) {
    this.r = null
};
twinsFamily.Boot.prototype = {
    preload: function() {
        game.load.image("container_load", "assets/container_load" + resolution + ".png");
        game.load.image("loadingbar_bg", "assets/loadingbar_bg" + resolution + ".png");
        game.load.image("preloadSprite01", "assets/preloadBar" + resolution + ".png");
        game.load.image("bgPreload", "assets/bgPreload" + resolution + ".png");
        game.load.image("logo_softgames", "assets/logo_softgames" + resolution + ".png");
        game.load.image("rotate", "assets/rotate" + resolution + ".png");
        game.load.atlasXML("sprites", "assets/sprites.png", "assets/sprites.xml")
    },
    create: function() {
        this.input.maxPointers = 1;
        if (game.device.desktop) {
            this.scale.scaleMode = Phaser.ScaleManager.SHOW_ALL
        } else {
            this.scale.scaleMode = Phaser.ScaleManager.EXACT_FIT;
            this.scale.forceOrientation(false, true);
            this.scale.enterIncorrectOrientation.add(this.enterIncorrectOrientation, this);
            this.scale.leaveIncorrectOrientation.add(this.leaveIncorrectOrientation, this)
        }
        this.scale.pageAlignHorizontally = true;
        this.scale.pageAlignVertically = true;
        game.scale.enterPortrait.add(this.rescale, this);
        game.scale.enterLandscape.add(this.rescale, this);
        this.scale.setScreenSize(true);
        SG_Hooks.setOrientationHandler(game.scale.checkOrientation);
        SG_Hooks.setResizeHandler(game.scale.checkResize);
        lang = SG.lang; //SG_Hooks.getLanguage(["en", "es", "de", "it", "fr", "pt", "tr", "ru", "th", "nl", "pl"]);
        text = text[lang];
        if (lang == "ru" || lang == "th" || lang == "pl" || lang == "tr") langFont = 'px "Play"';
        setTimeout("window.scrollTo(0, 1)", 10);
        if (game.device.desktop) {
            document.body.style.backgroundImage = 'url("assets/bgFsPreload2.png")';
            document.body.style.backgroundSize = "" + game.scale.width * 3.1796875 + "px 100%";
            document.body.style.backgroundPosition = "center"
        }
        game.state.start("preload")
    },
    rescale: function() {
        var _game = this.game;
        setTimeout(function() {
            _game.scale.refresh();
            setTimeout(function() {
                _game.scale.refresh()
            }, 400)
        }, 400)
    },
    enterIncorrectOrientation: function() {
        if (!orientated) {
            orientated = true;
            game.input.maxPointers = 0;
            if (r != null && r != undefined) r.destroy();
            r = game.add.sprite(0, game.camera.y, "rotate")
        }
    },
    leaveIncorrectOrientation: function() {
        if (orientated) {
            orientated = false;
            game.input.maxPointers = 1;
            r.destroy()
        }
    }
};

function TestLandscape() {
    if (game.device.desktop) return;
    game.time.events.add(400, function() {
        if (game.scale.isLandscape && !orientated) {
            orientated = true;
            game.input.maxPointers = 0;
            if (r != null && r != undefined) r.destroy();
            r = game.add.sprite(0, game.camera.y, "rotate")
        } else if (orientated) {
            if (r != null && r != undefined) r.destroy();
            r = game.add.sprite(0, game.camera.y, "rotate")
        }
    }, game)
}
