twinsFamily.Menu.prototype = {
    create: function() {
        this.add.image(0, 0, "bgMenu");
        this.logo = game.add.sprite(game.width / 2, 95 * resolution, "sprites");
        this.logo.frameName = "logo" + resolution + ".png";
        this.logo.alpha = 0;
        this.logo.scale.setTo(.2, .2);
        this.logo.anchor.setTo(.5, .5);
        game.time.events.add(500, function() {
            game.add.tween(this.logo.scale).to({
                x: 1,
                y: 1
            }, 700, Phaser.Easing.Back.Out, true, 200);
            game.add.tween(this.logo).to({
                alpha: 1
            }, 1e3, Phaser.Easing.Quadratic.Out, true);
            this.tween_play = game.add.tween(this.bnt_play.scale).to({
                x: 1.1,
                y: 1.1
            }, 1e3, Phaser.Easing.Quadratic.Out).to({
                x: .9,
                y: .9
            }, 1e3, Phaser.Easing.Quadratic.Out);
            this.tween_play.start();
            this.tween_play.loop()
        }, this);
        this.bnt_play = new Bouton(this.game, 0, 230 * resolution, "sprites", this.actionPlay, this);
        this.bnt_play.frameName = "playbtn" + resolution + ".png";
        this.bnt_play.x = game.width / 2;
        this.world.add(this.bnt_play);
        this.musicbnt = new Bouton(this.game, 275 * resolution, 230 * resolution, "sprites", this.actionMusic, this);
        this.musicbnt.frameName = "musicbnt" + resolution + ".png";
        this.world.add(this.musicbnt);
        this.bnt_moregames = new Bouton(this.game, 45 * resolution, 230 * resolution, "sprites", this.funcmoregames, this);
        this.bnt_moregames.frameName = "moreg" + resolution + ".png";
        this.world.add(this.bnt_moregames);
        if (Music.enableMisic) {
            this.musicbnt.frameName = "musicbnt" + resolution + ".png"
        } else {
            this.musicbnt.frameName = "Mutemusicbnt" + resolution + ".png"
        }
        if (game.device.desktop) {
            document.body.style.backgroundImage = 'url("assets/bgFsMenu2.png")';
            document.body.style.backgroundSize = "" + game.scale.width * 3.1796875 + "px 100%";
            document.body.style.backgroundPosition = "center"
        }
        TestLandscape()
    },
    actionMusic: function() {
        Music.enableMisic = !Music.enableMisic;
        if (Music.enableMisic) {
            this.musicbnt.frameName = "musicbnt" + resolution + ".png";
            Music.music.resume()
        } else {
            this.musicbnt.frameName = "Mutemusicbnt" + resolution + ".png";
            Music.music.pause()
        }
    },
    actionPlay: function() {
        SG_Hooks.start();
        play.InitialiseFade("levels")
    },
    funcmoregames: function() {
        SG.redirectToPortal();
        //window.open("http://m.softgames.de/")
    },
    update: function() {
        play.FadeNoire()
    }
};
