    initAtributs: function() {
        this.stateMusic = Music.enableMisic;
        this.timerEndLevel = null;
        this.timerEndLevelAndLose = null;
        this.istimerEndLevel = false;
        this.istimerEndLevelAndLose = false;
        this.gameOver = false;
        this.you_win = false;
        this.pausePlay = false;
        this.isEndAllLevels = false;
        this.number_fips = 4;
        this.nbr_to_match = 3;
        this.temps_hint = 4e3;
        this.health_ennemy = 10 + play.numLevel / 2;
        this.nbr_fruit_pw = 12;
        if (game.device.desktop) {
            this.tw_stop_time = 200
        } else {
            this.tw_stop_time = 150
        }
    },
    init_Fruits: function() {
        for (var i = 0; i < this.cols; i++) {
            for (var j = 0; j < this.rows; j++) {
                if (this.mat_types[i][j] >= 0) {
                    var sprite;
                    var rnd_frame = this.mat_types[i][j];
                    if (this.group_sprites.length <= 0) {
                        sprite = new Phaser.Sprite(this.game, this.beginX + j * this.taille + j * 3 * resolution, 440 * resolution - (this.cols - 1) * this.taille + this.taille * i + i * 3.5 * resolution, "obj", rnd_frame)
                    } else sprite = new Phaser.Sprite(this.game, this.beginX + j * this.taille + j * 3 * resolution, 440 * resolution - (this.cols - 1) * this.taille + this.taille * i + i * 3.5 * resolution, "obj", rnd_frame);
                    sprite.alive = true;
                    sprite.anchor.setTo(.5, 1);
                    sprite.isPw = false;
                    sprite.animations.add("splash", [sprite.frame + this.number_fips, sprite.frame + this.number_fips, sprite.frame + this.number_fips, sprite.frame + this.number_fips]);
                    sprite.frame = rnd_frame;
                    sprite.ind = sprite.frame;
                    sprite.to_char = false;
                    sprite.isSelected = false;
                    sprite.isHint = false;
                    sprite.txt_created = false;
                    if (sprite.tw != null) sprite.tw.pause();
                    sprite.tw = null;
                    sprite.initWidth = sprite.width;
                    sprite.initHeight = sprite.height;
                    sprite.tw_stop = game.add.tween(sprite).to({
                        width: sprite.initWidth * 1.2,
                        height: sprite.initHeight * .8
                    }, this.tw_stop_time, Phaser.Easing.Circular.None).to({
                        width: sprite.initWidth,
                        height: sprite.initHeight
                    }, this.tw_stop_time + 50, Phaser.Easing.Circular.None);
                    sprite.tw_stop.do_start = true;
                    sprite.tw_stop.isStart = false;
                    sprite.tw_stop.onComplete.add(function() {
                        if (this.isStart) {
                            play.nbr_tween_started--;
                            this.isStart = false
                        }
                    }, sprite.tw_stop);
                    switch (rnd_frame) {
                        case 0:
                            sprite.score = 10;
                            break;
                        case 1:
                            sprite.score = 15;
                            break;
                        case 2:
                            sprite.score = 20;
                            break;
                        case 3:
                            sprite.score = 30;
                            break
                    }
                    sprite.to_y = -1;
                    sprite.index_closer = -1;
                    sprite.y_index = i;
                    sprite.isMoving = false;
                    if (sprite.ind == 32 || sprite.ind == 33) {
                        sprite.sides_tested = 0
                    } else sprite.sides_tested = -1;
                    sprite.ind_i = i;
                    sprite.ind_j = j;
                    sprite.origin_ind = sprite.ind;
                    if (sprite.ind == 32 || sprite.ind == 33) {
                        this.mat_types[i][j] = 29
                    }
                    this.mat_fruits[i][j] = sprite;
                    this.mat_etat[i][j] = 1;
                    this.group_sprites.add(sprite)
                }
            }
        }
    },
