    buy_moves: function() {
        if (play.nbr_coins >= 220) {
            play.istimerEndLevelAndLose = false;
            play.timerEndLevelAndLose = -1;
            play.nbr_coins -= 220;
            play.last_nbr_coins -= 220;
            play.group_moves.getAt(2).setText("" + play.nbr_coins);
            play.number_moves += 3;
            play.txt_number_moves.setText("" + play.number_moves);
            play.txt_number_moves.x = play.txt_moves_word.x + play.txt_moves_word.width / 2 - play.txt_number_moves.width / 2;
            game.time.events.add(300, function() {
                if (Music.enableMisic && game.sound.usingWebAudio) Music.sounds.play("whoosh")
            }, play);
            game.add.tween(play.group_moves).to({
                y: -50 * resolution
            }, 350, Phaser.Easing.Quadratic.Out, true, 100).to({
                y: 400 * resolution
            }, 300, Phaser.Easing.Quadratic.Out, true).onComplete.add(function() {
                play.pausePlay = false;
                play.bg_noire.visible = false;
                play.bnt_pause.visible = true
            }, play);
            play.group_moves.forEach(function(obj) {
                game.add.tween(obj).to({
                    alpha: 0
                }, 600, Phaser.Easing.Quadratic.Out, true, 400)
            }, play)
        } else if (SG_Hooks.isEnabledIncentiviseButton()) play.showAddCoins();
        else {
            var txt_score_sp = game.add.text(this.x + this.width / 8, this.y - this.height / 2, text.txtNoEnoughCoins, {
                font: 16 * resolution + langFont,
                align: "center",
                fill: "#fff",
                stroke: "#27bac2",
                strokeThickness: 3 * resolution
            });
            txt_score_sp.x -= txt_score_sp.width / 2;
            txt_score_sp.y -= txt_score_sp.height / 2;
            txt_score_sp.initY = txt_score_sp.y;
            txt_score_sp.scale.setTo(.1, .1);
            game.add.tween(txt_score_sp.scale).to({
                x: 1,
                y: 1
            }, 400, Phaser.Easing.Quadratic.Out, true).onComplete.add(function() {
                game.add.tween(this).to({
                    y: this.initY - 30 * resolution,
                    alpha: 0
                }, 800, Phaser.Easing.Linear.None, true).onComplete.add(function() {
                    this.visible = false;
                    this.destroy()
                }, txt_score_sp)
            }, txt_score_sp)
        }
    },
    cancel_moves: function() {
        game.time.events.add(300, function() {
            if (Music.enableMisic && game.sound.usingWebAudio) Music.sounds.play("whoosh")
        }, this);
        game.add.tween(this.group_moves).to({
            y: -50 * resolution
        }, 350, Phaser.Easing.Quadratic.Out, true, 100).to({
            y: 400 * resolution
        }, 300, Phaser.Easing.Quadratic.Out, true).onComplete.add(function() {
            this.pausePlay = false;
            this.bg_noire.visible = false;
            this.bnt_pause.visible = true;
            this.game_over()
        }, this);
        this.group_moves.forEach(function(obj) {
            game.add.tween(obj).to({
                alpha: 0
            }, 600, Phaser.Easing.Quadratic.Out, true, 400)
        }, this)
    },
