    cancelAddCoins: function() {
        var context = this;
        if (context == play) {
            if (play.group_moves == null) context = play.group_shop;
            else context = play.group_moves
        }
        context.getAt(2).setText("" + play.nbr_coins);
        game.time.events.add(300, function() {
            if (Music.enableMisic && game.sound.usingWebAudio) Music.sounds.play("whoosh")
        }, play);
        game.add.tween(play.group_addcoins).to({
            y: -50 * resolution
        }, 350, Phaser.Easing.Quadratic.Out, true, 100).to({
            y: 400 * resolution
        }, 300, Phaser.Easing.Quadratic.Out, true).onComplete.add(function() {
            context.y = 400 * resolution;
            context.setAll("alpha", 0);
            game.add.tween(context).to({
                y: -50 * resolution
            }, 350, Phaser.Easing.Quadratic.Out, true, 100).to({
                y: -35 * resolution
            }, 200, Phaser.Easing.Quadratic.Out, true, 70);
            game.world.bringToTop(play.bg_noire);
            game.world.bringToTop(context);
            context.forEach(function(obj) {
                game.add.tween(obj).to({
                    alpha: 1
                }, 600, Phaser.Easing.Quadratic.Out, true, 150)
            }, context);
            if (this == play) {
                play.group_addcoins.getAt(4).setText(text.txtNoCoins);
                play.group_addcoins.getAt(4).y = play.group_addcoins.getAt(0).y - 85 * resolution
            } else {
                play.group_addcoins.getAt(4).setText(text.txtAddCoins);
                play.group_addcoins.getAt(4).y = play.group_addcoins.getAt(0).y - 75 * resolution
            }
            play.group_addcoins.getAt(4)._fontSize = 18 * resolution;
            play.group_addcoins.getAt(4).x = game.width / 2 - play.group_addcoins.getAt(4).width / 2 + 2 * resolution;
            play.group_addcoins.getAt(11).setText(text.txtFree);
            play.group_addcoins.getAt(11).x = play.group_addcoins.getAt(5).x - play.group_addcoins.getAt(11).width / 2;
            play.group_addcoins.getAt(5).visible = true;
            play.group_addcoins.getAt(6).visible = true;
            play.group_addcoins.getAt(7).visible = true;
            play.group_addcoins.getAt(8).visible = false;
            play.group_addcoins.getAt(9).visible = false;
            play.group_addcoins.getAt(10).visible = false
        }, context);
        play.group_addcoins.forEach(function(obj) {
            game.add.tween(obj).to({
                alpha: 0
            }, 600, Phaser.Easing.Quadratic.Out, true, 400)
        }, play)
    },
