        this.info_txt_price.alive = true;
        this.info_bnt_renforcer = new Bouton(game, this.bg_info.x, this.bg_info.y + this.bg_info.height / 2 - 40 * resolution, "sprites", this.funcRenforcer, this);
        this.info_bnt_renforcer.frameName = "bnt_upgrade" + resolution + ".png";
