    showAddCoins: function() {
        ch.plus_bnt.onInputUp.active = false;
        ch.group_addcoins.setAll("visible", true);
        ch.bg_noire.visible = true;
        ch.group_addcoins.getAt(3).setText("" + coins);
        ch.group_addcoins.getAt(3).x = ch.group_addcoins.getAt(2).x - ch.group_addcoins.getAt(3).width / 2 + 10 * resolution;
        ch.group_addcoins.getAt(8).visible = false;
        ch.group_addcoins.getAt(9).visible = false;
        ch.group_addcoins.getAt(10).visible = false;
        ch.group_addcoins.getAt(12).visible = false;
        ch.group_addcoins.getAt(11).scale.setTo(1, 1);
        var context = ch.group_info;
        ch.group_addcoins.getAt(4).setText(text.txtNoCoins);
        ch.group_addcoins.getAt(4).x = game.width / 2 - ch.group_addcoins.getAt(4).width / 2 + 2 * resolution;
        ch.group_addcoins.getAt(4).y = ch.group_addcoins.getAt(0).y - 80 * resolution;
        if (Music.enableMisic && game.sound.usingWebAudio) Music.sounds.play("whoosh");
        if (this != ch.plus_bnt && ch.group_info.y < 50 * resolution) {
            game.add.tween(context).to({
                y: -50 * resolution
            }, 350, Phaser.Easing.Quadratic.Out, true, 100).to({
                y: 400 * resolution
            }, 300, Phaser.Easing.Quadratic.Out, true);
            context.forEach(function(obj) {
                game.add.tween(obj).to({
                    alpha: 0
                }, 600, Phaser.Easing.Quadratic.Out, true, 400)
            }, ch);
            ch.context = ch
        } else {
            ch.context = ch.plus_bnt
        }
        ch.group_addcoins.setAll("alpha", 0);
        game.add.tween(ch.group_addcoins).to({
            y: -50 * resolution
        }, 350, Phaser.Easing.Quadratic.Out, true, 100).to({
            y: -35 * resolution
        }, 200, Phaser.Easing.Quadratic.Out, true, 70);
        game.world.bringToTop(ch.bg_noire);
        game.world.bringToTop(ch.group_addcoins);
        ch.group_addcoins.forEach(function(obj) {
            game.add.tween(obj).to({
                alpha: 1
            }, 600, Phaser.Easing.Quadratic.Out, true, 150)
        }, ch)
    },
