            if (lang == "ru" || lang == "fr") ch.group_addcoins.getAt(4)._fontSize = 15 * resolution;
            else ch.group_addcoins.getAt(4)._fontSize = 18 * resolution;
            ch.group_addcoins.getAt(4).x = game.width / 2 - ch.group_addcoins.getAt(4).width / 2 + 2 * resolution;
